import{_ as i,C as o,o as s,c as r,j as e,a,E as n,ag as c}from"./chunks/framework.HG0H2VLS.js";const x=JSON.parse('{"title":"AiAssistant","description":"","frontmatter":{},"headers":[],"relativePath":"cc-templates/ai-assistant.md","filePath":"cc-templates/ai-assistant.md"}'),l={name:"cc-templates/ai-assistant.md"};function h(p,t,m,u,g,b){const d=o("ComponentDemo");return s(),r("div",null,[t[0]||(t[0]=e("hr",null,null,-1)),t[1]||(t[1]=e("h2",{id:"title-aiassistant",tabindex:"-1"},[a("title: AiAssistant "),e("a",{class:"header-anchor",href:"#title-aiassistant","aria-label":'Permalink to "title: AiAssistant"'},"​")],-1)),t[2]||(t[2]=e("h1",{id:"aiassistant",tabindex:"-1"},[a("AiAssistant "),e("a",{class:"header-anchor",href:"#aiassistant","aria-label":'Permalink to "AiAssistant"'},"​")],-1)),n(d,{src:"/demos/src/cc/templates/AiAssistant/AiAssistant.html"}),t[3]||(t[3]=c('<h2 id="variant-matrix" tabindex="-1">Variant matrix <a class="header-anchor" href="#variant-matrix" aria-label="Permalink to &quot;Variant matrix&quot;">​</a></h2><p>Single Type axis, 3 variants. All three states are present in the same demo HTML and switched via JS class on <code>.chat-main</code> (<code>--initial</code> / <code>--processing</code> / <code>--response</code>), mirroring the existing <code>AiChatMinimised</code> template behaviour.</p><table tabindex="0"><thead><tr><th>Node</th><th>Type</th><th>Notes</th></tr></thead><tbody><tr><td><code>4151:8248</code></td><td>Initial</td><td>Custom welcome paragraph block — different from the standard AI Chat (no SuggestedQuestion grid).</td></tr><tr><td><code>4152:8324</code></td><td>Processing</td><td>Standard ChatMain Processing: WorkingIntro + SourcesCarousel + Skeleton lines.</td></tr><tr><td><code>4152:8899</code></td><td>Response</td><td>Standard ChatMain Response: MessageBubble + SourcesCarousel + response prose.</td></tr></tbody></table><hr><h2 id="relationship-to-aichatminimised" tabindex="-1">Relationship to AiChatMinimised <a class="header-anchor" href="#relationship-to-aichatminimised" aria-label="Permalink to &quot;Relationship to AiChatMinimised&quot;">​</a></h2><p>This is a <strong>CC-themed sibling</strong> of <code>src/templates/AiChatMinimised/</code>:</p><table tabindex="0"><thead><tr><th>Property</th><th>AiChatMinimised (AI Chat)</th><th>AiAssistant (CC)</th></tr></thead><tbody><tr><td>Width</td><td>384px (<code>--ai-size-7</code>)</td><td>320px (<code>--ai-size-6</code>)</td></tr><tr><td>Theme</td><td>AI default</td><td><code>data-brand=&quot;cc&quot;</code></td></tr><tr><td>Header title</td><td>Assistant selector dropdown (&quot;Support Assistant ▾&quot;)</td><td>Plain text &quot;Affino Assistant&quot;</td></tr><tr><td>Initial screen</td><td>SuggestedQuestion grid + intro</td><td>Custom welcome paragraphs only</td></tr><tr><td>Processing / Response</td><td>Standard ChatMain</td><td>Same standard ChatMain</td></tr><tr><td>Drag</td><td>Header surface</td><td>Same (id <code>drag-handle</code>)</td></tr><tr><td>Resize</td><td>Top-edge vertical handle (<code>cursor: ns-resize</code>)</td><td>Same handle reused verbatim</td></tr><tr><td>Sidebar</td><td>Slide-in overlay on PanelLeft toggle</td><td>Same overlay + same content</td></tr><tr><td>Maximise</td><td>Links to AI Chat full page</td><td><strong>Visual only</strong> for now (user-deferred)</td></tr><tr><td>Close</td><td>Hides widget</td><td>Same</td></tr></tbody></table><p>The CSS / HTML structure is a clone of AiChatMinimised with <code>.ai-chat-min</code> → <code>.ai-assistant</code> rename, <code>--ai-size-7</code> → <code>--ai-size-6</code>, and the simplified header + custom Initial content.</p><hr><h2 id="css-class-mapping" tabindex="-1">CSS class mapping <a class="header-anchor" href="#css-class-mapping" aria-label="Permalink to &quot;CSS class mapping&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Figma</th><th>CSS</th></tr></thead><tbody><tr><td>Wrapper (<code>AiAssistant</code>)</td><td><code>.ai-assistant</code> (<code>&lt;div&gt;</code>)</td></tr><tr><td>Top-edge resize</td><td><code>.ai-assistant__resize-handle</code></td></tr><tr><td>Header (drag surface)</td><td><code>.chat-header.chat-header--minimised.ai-assistant__header</code></td></tr><tr><td>Title text &quot;Affino Assistant&quot;</td><td><code>.ai-assistant__title</code></td></tr><tr><td>Sidebar overlay</td><td><code>.ai-assistant__overlay</code></td></tr><tr><td>Slide-in sidebar</td><td><code>.ai-assistant__sidebar</code> (composes existing <code>.chat-sidebar</code>)</td></tr><tr><td>Main content area</td><td><code>.ai-assistant__main</code> (composes <code>.chat-main</code>)</td></tr><tr><td>Initial inner override</td><td><code>.ai-assistant__initial-inner</code> (replaces <code>chat-main__initial-inner</code> gap/padding)</td></tr><tr><td>Custom welcome paragraphs</td><td><code>.ai-assistant__welcome</code></td></tr><tr><td>Hidden state (close)</td><td><code>.ai-assistant--hidden</code></td></tr><tr><td>Drag-active no-transition</td><td><code>.ai-assistant--no-transition</code></td></tr><tr><td>Resize-active state</td><td><code>.ai-assistant--resizing</code></td></tr><tr><td>Sidebar-open state</td><td><code>.ai-assistant--sidebar-open</code></td></tr></tbody></table><hr><h2 id="token-mapping" tabindex="-1">Token mapping <a class="header-anchor" href="#token-mapping" aria-label="Permalink to &quot;Token mapping&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Property</th><th>Token</th><th>Notes</th></tr></thead><tbody><tr><td>Width</td><td><code>var(--ai-size-6)</code> (320px)</td><td>Figma default. User-resizable via top-edge handle.</td></tr><tr><td>Height</td><td><code>var(--_panel-height, 668px)</code></td><td>CSS variable set by resize JS. Min 320px. Max 100vh − 48px.</td></tr><tr><td>Border-radius</td><td><code>var(--ai-radius-xl)</code> (24px)</td><td></td></tr><tr><td>Background</td><td><code>var(--ai-surface-primary)</code></td><td></td></tr><tr><td>Shadow</td><td><code>var(--ai-shadow-lg)</code></td><td></td></tr><tr><td>Header border-bottom</td><td><code>1px solid var(--ai-border-secondary)</code></td><td></td></tr><tr><td>Title font</td><td><code>var(--ai-font-body)</code> semibold, <code>var(--ai-font-fixed-xs)</code> (14px), <code>var(--ai-leading-md)</code></td><td></td></tr><tr><td>Title colour</td><td><code>var(--ai-text-primary)</code></td><td></td></tr><tr><td>Welcome paragraphs</td><td><code>var(--ai-font-body)</code> regular, <code>var(--ai-font-fluid-sm)</code> (14px), line-height 1.5</td><td></td></tr><tr><td>Welcome colour</td><td><code>var(--ai-text-secondary)</code></td><td></td></tr></tbody></table><p>All values come from existing <code>--ai-*</code> semantic tokens. No token gaps — the CC theme picks up <code>data-brand=&quot;cc&quot;</code> and re-paints surfaces / brand colours via the tokens-cc.css overrides.</p><hr><h2 id="interactions" tabindex="-1">Interactions <a class="header-anchor" href="#interactions" aria-label="Permalink to &quot;Interactions&quot;">​</a></h2><p><strong>Drag</strong> — header acts as drag handle (<code>id=&quot;drag-handle&quot;</code>). Pointerdown → track deltas → translate position with CSS variables. Click on a button inside the header (sidebar-toggle / maximise / close) does NOT initiate drag because the listener checks <code>closest(&#39;button&#39;)</code> first.</p><p><strong>Resize</strong> — top-edge handle (<code>#resize-handle</code>) with <code>cursor: ns-resize</code>. Pointerdown → tracks vertical delta → updates <code>--_panel-height</code>. Min 320px, max <code>calc(100vh - var(--ai-spacing-6) * 2)</code>.</p><p><strong>Sidebar</strong> — PanelLeft button toggles <code>.ai-assistant--sidebar-open</code>. CSS slide-in via <code>transform: translateX(-100%) → 0</code>. Overlay click also closes.</p><p><strong>Close</strong> — hides via <code>.ai-assistant--hidden { display: none }</code>.</p><p><strong>Maximise</strong> — button rendered but no click handler yet. User-deferred — will route to a full-page CC AI Chat when that template lands.</p><p><strong>Chat-state transitions</strong> — Initial → Processing → Response handled by ChatMain.js auto-init (existing). Click a Suggested Question (none in Initial here, so direct submit) or submit the textarea → transitions via GSAP.</p><hr><h2 id="token-gaps" tabindex="-1">Token gaps <a class="header-anchor" href="#token-gaps" aria-label="Permalink to &quot;Token gaps&quot;">​</a></h2><p>None. All values map to existing <code>--ai-*</code> tokens.</p><hr><h2 id="history" tabindex="-1">History <a class="header-anchor" href="#history" aria-label="Permalink to &quot;History&quot;">​</a></h2><ul><li>2026-05-27: Initial template scaffold. Cloned from <code>src/templates/AiChatMinimised/</code> with <code>.ai-chat-min</code> → <code>.ai-assistant</code> rename and <code>--ai-size-7</code> → <code>--ai-size-6</code> (384 → 320px). Header simplified (assistant selector removed, replaced with plain &quot;Affino Assistant&quot; title). Initial state replaced with the verbatim welcome paragraph block from Figma <code>4151:8248</code>. CC theme via <code>data-brand=&quot;cc&quot;</code> on <code>&lt;html&gt;</code>. Drag + top-edge resize JS reused verbatim. Maximise button kept visual-only pending the full-page CC AI Chat template.</li></ul><h2 id="notes" tabindex="-1">Notes <a class="header-anchor" href="#notes" aria-label="Permalink to &quot;Notes&quot;">​</a></h2><ul><li><code>--ai-size-6</code> resolves to 320px — matches the Figma frame width exactly.</li><li>The Initial screen IS the only structural divergence from the standard chat pattern. Once the user submits a question it transitions to Processing / Response which use the standard ChatMain markup. Both inherit the mobile- pinning rules from <code>AiAssistant.css</code> lines ~145+ (reused from AiChatMinimised).</li><li>The internal sidebar reuses the full ChatSidebar component with its existing Pinned/Recent/Older sections and item menus.</li></ul><hr>',32))])}const C=i(l,[["render",h]]);export{x as __pageData,C as default};
